def solve(well_parameters, optimization_constraints):
    # Validate inputs vs contract
    if not isinstance(well_parameters, dict) or not isinstance(optimization_constraints, dict):
        raise ValueError("Invalid input types. Expected dictionaries for well_parameters and optimization_constraints.")

    # Check required keys in well_parameters
    required_keys = ['depth', 'angle', 'length']
    for key in required_keys:
        if key not in well_parameters:
            raise ValueError(f"Missing required key in well_parameters: {key}")

    # Check required keys in optimization_constraints
    required_constraints = ['max_depth', 'min_angle', 'max_length']
    for key in required_constraints:
        if key not in optimization_constraints:
            raise ValueError(f"Missing required key in optimization_constraints: {key}")

    # Implement core logic
    depth = well_parameters['depth']
    angle = well_parameters['angle']
    length = well_parameters['length']

    max_depth = optimization_constraints['max_depth']
    min_angle = optimization_constraints['min_angle']
    max_length = optimization_constraints['max_length']

    # Simple optimization logic (example)
    if depth > max_depth:
        depth = max_depth
    if angle < min_angle:
        angle = min_angle
    if length > max_length:
        length = max_length

    optimized_parameters = {
        'optimized_depth': depth,
        'optimized_angle': angle,
        'optimized_length': length
    }

    return optimized_parameters
